    // ── Classification Reference Test ──

    [TestMethod(Timeout = 120000)]
    public async Task Reference_SqueezeNet_MatchesOnnxRuntime() => await RunTest(async accelerator =>
    {
        var (actual, expected) = await RunReferenceComparison(accelerator,
            "models/squeezenet/model.onnx",
            "references/squeezenet/cat_input_nchw.bin",
            "references/squeezenet/cat_output.bin",
            new[] { 1, 3, 224, 224 });
        AssertReferenceMatch(actual, expected, 0.1f, "SqueezeNet");

        // Also verify top-1 is a cat class (281-285)
        int topIdx = 0;
        for (int i = 1; i < actual.Length; i++)
            if (actual[i] > actual[topIdx]) topIdx = i;
        if (topIdx < 281 || topIdx > 285)
            throw new Exception($"[SqueezeNet] Top class {topIdx}, expected cat (281-285)");
    });

    // ── Super Resolution Reference Test ──

    [TestMethod(Timeout = 120000)]
    public async Task Reference_ESPCN_MatchesOnnxRuntime() => await RunTest(async accelerator =>
    {
        if (accelerator.AcceleratorType == AcceleratorType.CPU)
            throw new UnsupportedTestException("ESPCN too slow on CPU");

        var (actual, expected) = await RunReferenceComparison(accelerator,
            "models/super-resolution/model.onnx",
            "references/super-resolution/cat_input_y.bin",
            "references/super-resolution/cat_output_y.bin",
            new[] { 1, 1, 224, 224 });
        // ESPCN output is Y-channel [0,1] — tighter tolerance
        AssertReferenceMatch(actual, expected, 0.01f, "ESPCN");
    });

    // ── Object Detection Reference Test ──

    [TestMethod(Timeout = 120000)]
    public async Task Reference_YOLOv8_MatchesOnnxRuntime() => await RunTest(async accelerator =>
    {
        // Enable per-node capture to trace the detection head
        Graph.GraphExecutor.CapturedOutputs = new Dictionary<string, float[]>();
        try
        {
            var (actual, expected) = await RunReferenceComparison(accelerator,
                "models/yolov8n/model.onnx",
                "references/yolov8n/cat_input_nchw.bin",
                "references/yolov8n/cat_output.bin",
                new[] { 1, 3, 640, 640 });

            // Dump captured DFL/decode head values for debugging
            var captured = Graph.GraphExecutor.CapturedOutputs;
            var sb = new System.Text.StringBuilder();
            sb.AppendLine($"Captured {captured.Count} nodes. Last 30:");
            foreach (var (key, vals) in captured.OrderBy(kv => kv.Key).TakeLast(30))
            {
                var vStr = string.Join(", ", vals.Take(5).Select(v => v.ToString("F4")));
                sb.AppendLine($"  {key}: [{vStr}]");
            }
            sb.AppendLine($"FINAL actual[0..5]: [{string.Join(", ", actual.Take(5).Select(v => v.ToString("F4")))}]");
            sb.AppendLine($"FINAL expected[0..5]: [{string.Join(", ", expected.Take(5).Select(v => v.ToString("F4")))}]");

            AssertReferenceMatch(actual, expected, 1.0f, $"YOLOv8\n{sb}");
        }
        finally
        {
            Graph.GraphExecutor.CapturedOutputs = null;
        }
    });
}
